mapper.select:
SELECT id, event_type, event_category, risk_level, result, actor_type,
       actor_user_id, actor_client_id, target_type, target_id, session_id,
       reason_code, reason_detail, change_summary::text, correlation_id, occurred_at
  FROM iam_security_audit_event
 WHERE 1 = 1

   AND event_category = #{category}


   AND target_id = #{targetId}

 ORDER BY occurred_at DESC
 LIMIT #{limit} OFFSET #{offset}
